/**
 * Подтема PlasmaHomeDsTheme.OnLight
 */
@Composable
public fun PlasmaHomeDsTheme.OnLight(
    isDark: Boolean = isSystemInDarkTheme(),
    content: @Composable
    () -> Unit,
) {
    val currentColors = LocalPlasmaHomeDsColors.current
    val overrideColors = currentColors.copyAttrs(OnLightColorsOverride)
    val currentGradients = LocalPlasmaHomeDsGradients.current
    val overrideGradients = currentGradients.copyAttrs(OnLightGradientsOverride)
    PlasmaHomeDsTheme(
        colors = overrideColors,
        gradients = overrideGradients,
        content = content,
    )
}
